package com.conduit.nexus

import androidx.compose.ui.graphics.Color
import androidx.compose.ui.text.AnnotatedString
import androidx.compose.ui.text.SpanStyle
import androidx.compose.ui.text.input.OffsetMapping
import androidx.compose.ui.text.input.TransformedText
import androidx.compose.ui.text.input.VisualTransformation
import androidx.compose.ui.text.withStyle
import java.util.regex.Pattern

class PythonSyntaxTransformation : VisualTransformation {
    override fun filter(text: AnnotatedString): TransformedText {
        return TransformedText(highlightPython(text.text), OffsetMapping.Identity)
    }
}

fun highlightPython(code: String): AnnotatedString {
    val keywords = Pattern.compile("\\b(def|class|if|else|elif|while|for|return|import|from|as|try|except|finally|with|pass|break|continue|print|None|True|False|in|is|not|and|or|lambda)\\b")
    val strings = Pattern.compile("\".*?\"|'.*?'")
    val comments = Pattern.compile("#.*")
    val numbers = Pattern.compile("\\b\\d+\\b")
    val functions = Pattern.compile("\\b[a-zA-Z_][a-zA-Z0-9_]*(?=\\()")

    return AnnotatedString.Builder().apply {
        append(code)

        val matcherKeywords = keywords.matcher(code)
        while (matcherKeywords.find()) {
            addStyle(SpanStyle(color = Color(0xFF569CD6)), matcherKeywords.start(), matcherKeywords.end())
        }

        val matcherStrings = strings.matcher(code)
        while (matcherStrings.find()) {
            addStyle(SpanStyle(color = Color(0xFFCE9178)), matcherStrings.start(), matcherStrings.end())
        }

        val matcherFunctions = functions.matcher(code)
        while (matcherFunctions.find()) {
            addStyle(SpanStyle(color = Color(0xFFDCDCAA)), matcherFunctions.start(), matcherFunctions.end())
        }

        val matcherNumbers = numbers.matcher(code)
        while (matcherNumbers.find()) {
            addStyle(SpanStyle(color = Color(0xFFB5CEA8)), matcherNumbers.start(), matcherNumbers.end())
        }

        val matcherComments = comments.matcher(code)
        while (matcherComments.find()) {
            addStyle(SpanStyle(color = Color(0xFF6A9955)), matcherComments.start(), matcherComments.end())
        }
    }.toAnnotatedString()
}

